	item.style.cssText = "padding:3px 12px;cursor:pointer;white-space:nowrap;";
	item.addEventListener("mouseenter", function() { item.style.background = "#555"; });
	item.addEventListener("mouseleave", function() { item.style.background = ""; });
	item.addEventListener("click", function(e) {
		e.stopPropagation();
		e.preventDefault();
		onClick(e);
	});
	return item;
}

// Render icons once at startup and cache them
var editIconHTML = "";
function getEditIconHTML() {
	if(!editIconHTML) {
		editIconHTML = renderIconHTML("{{$:/core/images/edit-button}}");
	}
	return editIconHTML;
}

var viewIconHTML = "";
function getViewIconHTML() {
	if(!viewIconHTML) {
		viewIconHTML = renderIconHTML("{{$:/core/images/preview-open}}");
	}
	return viewIconHTML;
}

var linkIconHTML = "";
function getLinkIconHTML() {
	if(!linkIconHTML) {
		linkIconHTML = renderIconHTML("{{$:/core/images/link}}");
	}
	return linkIconHTML;
}

exports.startup = function() {
	// Patch TW's popup handler to ignore clicks inside sourcepos panels.
	// TW's Popup uses a capture-phase click listener on rootElement to dismiss popups.
	// We can't use stopPropagation (it blocks our own handlers too).
	// Instead, wrap handleEvent to skip clicks inside our panels.
	var origHandleEvent = $tw.popup.handleEvent.bind($tw.popup);
	$tw.popup.handleEvent = function(event) {
		if(event.type === "click" && event.target.closest &&
			event.target.closest(".sourcepos-var-inspector, #sourcepos-source-viewer, #sourcepos-context-menu")) {
			return;
		}
		return origHandleEvent(event);
	};
	// Hover tooltip with 400ms delay
	var hoverTimer = null;
	var tooltip = null;
	function removeTooltip() {
		if(hoverTimer) {
			clearTimeout(hoverTimer);
			hoverTimer = null;
		}
		if(tooltip) {
			tooltip.remove();
			tooltip = null;
		}
	}
	document.addEventListener("mouseover", function(event) {
		if(!$tw.wiki.trackSourcePositions || sharedState.isResizing) {
			return;
		}
		var info = findSourcePos(event.target);
		if(!info) {
			removeTooltip();
			return;
		}
		// Capture mouse position for tooltip placement
		var mouseX = event.clientX;
		var mouseY = event.clientY;
		// Restart timer on each mouseover (handles moving between nested elements)
		removeTooltip();
		hoverTimer = setTimeout(function() {
			hoverTimer = null;
			// Build tooltip text
			var text = info.raw;
			var context = info.element.getAttribute("data-source-context");
			if(context) {
				text += "  \u00BB " + context;
			}
			// Shorten caller chain for tooltip: max 3, skip callers matching context
			if(info.caller) {
				var callerLines = info.caller.split("\n");
				var short = callerLines.filter(function(c) {
					return !context || c.indexOf(context) === -1;
				});
				if(short.length > 3) {
					short = short.slice(0, 3);
					short.push("\u2190 +" + (callerLines.length - 3) + " more");
				}
				if(short.length > 0) {
					text += "\n" + short.join("\n");
				}
			}
			tooltip = document.createElement("div");
			tooltip.style.cssText = "position:fixed;background:rgba(40,40,40,0.95);color:#ffd;font-family:monospace;line-height:1.4;padding:2px 6px;border-radius:2px;white-space:pre;z-index:10000;pointer-events:none;";
			// Header line (bigger)
			var tipHeader = document.createElement("div");
			tipHeader.textContent = text.split("\n")[0];
			tipHeader.style.fontSize = "13px";
			tooltip.appendChild(tipHeader);
			// Remaining lines (smaller)
			var restLines = text.split("\n").slice(1).join("\n");
			if(restLines) {
				var tipBody = document.createElement("div");
				tipBody.textContent = restLines;
				tipBody.style.fontSize = "11px";
				tooltip.appendChild(tipBody);
			}
			document.body.appendChild(tooltip);
			// Position: prefer above the element, fall back to near mouse if no space
			var rect = info.element.getBoundingClientRect();
			var tipHeight = tooltip.offsetHeight;
			var tipWidth = tooltip.offsetWidth;
			var left = Math.min(rect.left, window.innerWidth - tipWidth - 4);
			if(left < 0) left = 4;
			if(rect.top - tipHeight - 4 >= 0) {
				// Enough space above
				tooltip.style.left = left + "px";
				tooltip.style.top = (rect.top - tipHeight - 4) + "px";
			} else {
				// Not enough space above — show near mouse, below cursor
				tooltip.style.left = Math.min(mouseX + 8, window.innerWidth - tipWidth - 4) + "px";
				tooltip.style.top = Math.min(mouseY + 16, window.innerHeight - tipHeight - 4) + "px";
			}
		}, 400);
	}, true);
	document.addEventListener("mouseout", function(event) {
		if(!event.relatedTarget || !findSourcePos(event.relatedTarget)) {
			removeTooltip();
		}
	}, true);
	// Right-click: show sourcepos context menu (Ctrl+right-click = native browser menu)
	document.addEventListener("contextmenu", function(event) {
		if(!$tw.wiki.trackSourcePositions) {
			return;
		}
		// Ctrl+right-click: let native browser context menu through
		if(event.ctrlKey) {
			return;
		}
		var info = findSourcePos(event.target);
		if(!info) {
			return;
		}
		// Remove any previous sourcepos context menu
		var existing = document.getElementById("sourcepos-context-menu");
		if(existing) {
			existing.remove();
		}
		event.preventDefault();
		// Create context menu
		var menu = document.createElement("div");
		menu.id = "sourcepos-context-menu";
		menu.style.cssText = "position:fixed;z-index:99999;background:#333;color:#eee;border-radius:4px;padding:2px 0;font-size:13px;box-shadow:0 2px 8px rgba(0,0,0,0.3);max-width:500px;";
		// Cleanup function: removes menu and its document-level event listeners
		var closeMenu, closeOnEscape;
		var removeMenu = function() {
			menu.remove();
			document.removeEventListener("click", closeMenu, true);
			document.removeEventListener("keydown", closeOnEscape, true);
		};
		// Position set after appending (need dimensions first)
		var menuX = event.clientX;
		var menuY = event.clientY;
		// Extract the edit-at-position function so it can be used by both icon and menu item
		var rangeInfo = sourcePosUtils.parseRange(info.range);
		var editAtPosition = function() {
			var title = info.tiddler;
			var story = new $tw.Story();
			var tiddler = $tw.wiki.getTiddler(title);
			var draftTitle;
			if(tiddler && tiddler.fields["draft.of"]) {
				draftTitle = title;
			} else {
				draftTitle = $tw.wiki.findDraft(title);
				if(!draftTitle) {
					story.navigateTiddler(title);
					draftTitle = $tw.wiki.generateDraftTitle(title);
					var draftTiddler = new $tw.Tiddler(
						{text: ""},
						tiddler,
						{
							title: draftTitle,
							"draft.title": title,
							"draft.of": title
						},
						$tw.wiki.getModificationFields()
					);
					$tw.wiki.addTiddler(draftTiddler);
					var storyList = story.getStoryList();
					var idx = storyList.indexOf(title);
					if(idx !== -1) {
						storyList[idx] = draftTitle;
					} else {
						storyList.unshift(draftTitle);
					}
					story.saveStoryList(storyList);
				}
			}
			var animDuration = parseInt($tw.wiki.getTiddlerText("$:/config/AnimationDuration", "400"), 10) || 400;
			var selectRange = function(retries) {
				var tiddlerEl = document.querySelector("[data-tiddler-title=\"" + draftTitle.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\]/g, "\\]") + "\"]");
				if(!tiddlerEl) {
					if(retries > 0) setTimeout(function() { selectRange(retries - 1); }, 200);
					return;
				}
				var textarea = null;
				var iframe = tiddlerEl.querySelector("iframe.tc-edit-texteditor-body");
				if(!iframe) {
					iframe = tiddlerEl.querySelector("iframe.tc-edit-texteditor");
				}
				if(iframe && iframe.contentDocument) {
					textarea = iframe.contentDocument.querySelector("textarea");
				}
				if(!textarea) {
					textarea = tiddlerEl.querySelector("textarea.tc-edit-texteditor-body");
				}
				if(!textarea) {
					textarea = tiddlerEl.querySelector("textarea.tc-edit-texteditor");
				}
				if(!textarea) {
					if(retries > 0) setTimeout(function() { selectRange(retries - 1); }, 200);
					return;
				}
				if(!textarea.value && retries > 0) {
					setTimeout(function() { selectRange(retries - 1); }, 200);
					return;
				}
				var startChar = info.charStart;
				var endChar = info.charEnd;
				if(isNaN(startChar) || isNaN(endChar)) {
					startChar = 0;
					endChar = 0;
				}
				textarea.focus();
				textarea.setSelectionRange(startChar, endChar);
				var textBeforeStart = textarea.value.substring(0, startChar);
				var lineNumber = textBeforeStart.split("\n").length;
				var ownerWindow = textarea.ownerDocument.defaultView || window;
				var lineHeight = parseFloat(ownerWindow.getComputedStyle(textarea).lineHeight) || 16;
				var selectionOffsetInTextarea = lineNumber * lineHeight;
				var editorEl = iframe || textarea;
				var editorRect = editorEl.getBoundingClientRect();
				var selectionScreenY = editorRect.top + selectionOffsetInTextarea;
				if(selectionScreenY < 0 || selectionScreenY > window.innerHeight) {
					window.scrollBy({ top: selectionScreenY - (window.innerHeight / 3), behavior: "instant" });
				}
			};
			setTimeout(function() { selectRange(5); }, animDuration + 100);
			removeMenu();
		};
		// Header: source position with edit icon button
		var header = document.createElement("div");
		header.style.cssText = "padding:3px 12px;color:#ffd;font-family:monospace;font-size:1rem;border-bottom:1px solid #555;white-space:pre-wrap;display:flex;align-items:center;justify-content:space-between;gap:8px;";
		var headerText = document.createElement("span");
		headerText.textContent = info.raw;
		header.appendChild(headerText);
		var headerBtnStyle = "cursor:pointer;flex-shrink:0;padding:2px 6px;border-radius:3px;font-size:14px;color:#999;fill:#999;";
		var headerBtnEnter = function(btn) { btn.style.color = "#fff"; btn.style.fill = "#fff"; btn.style.background = "rgba(255,255,255,0.15)"; };
		var headerBtnLeave = function(btn) { btn.style.color = "#999"; btn.style.fill = "#999"; btn.style.background = ""; };
		// Edit icon button
		if(rangeInfo) {
			var editBtn = document.createElement("span");
			editBtn.innerHTML = getEditIconHTML();
			editBtn.title = "Edit at " + info.range;
			editBtn.style.cssText = headerBtnStyle + "font-size:0;line-height:0;";
			var svg = editBtn.querySelector("svg");
			if(svg) { svg.setAttribute("width", "14px"); svg.setAttribute("height", "14px"); }
			editBtn.addEventListener("mouseenter", function() { headerBtnEnter(editBtn); });
			editBtn.addEventListener("mouseleave", function() { headerBtnLeave(editBtn); });
			editBtn.addEventListener("click", editAtPosition);
			header.appendChild(editBtn);
		}
		// Show source icon button
		if(rangeInfo) {
			var viewBtn = document.createElement("span");
			viewBtn.innerHTML = getViewIconHTML();
			viewBtn.title = "Show source";
			viewBtn.style.cssText = headerBtnStyle + "font-size:0;line-height:0;";
			var viewSvg = viewBtn.querySelector("svg");
			if(viewSvg) { viewSvg.setAttribute("width", "14px"); viewSvg.setAttribute("height", "14px"); }
			viewBtn.addEventListener("mouseenter", function() { headerBtnEnter(viewBtn); });
			viewBtn.addEventListener("mouseleave", function() { headerBtnLeave(viewBtn); });
			viewBtn.addEventListener("click", function() {
				sourceViewer.addEntry(info, editAtPosition);
				removeMenu();
			});
			header.appendChild(viewBtn);
		}
		// Close button
		var menuCloseBtn = document.createElement("span");
		menuCloseBtn.textContent = "\u2715";
		menuCloseBtn.style.cssText = headerBtnStyle;
		menuCloseBtn.addEventListener("mouseenter", function() { headerBtnEnter(menuCloseBtn); });
		menuCloseBtn.addEventListener("mouseleave", function() { headerBtnLeave(menuCloseBtn); });
		menuCloseBtn.addEventListener("click", function() { removeMenu(); });
		header.appendChild(menuCloseBtn);
		menu.appendChild(header);
		// Menu item: Copy tiddler title
		menu.appendChild(makeMenuItem("Copy tiddler title", function() {
			navigator.clipboard.writeText(info.tiddler);
			removeMenu();
		}));
		// Menu item: Copy source position (includes context and caller chain)
		menu.appendChild(makeMenuItem("Copy source position", function() {
			var text = info.raw;
			if(info.context) {
				text += "  \u00BB " + info.context;
			}
			if(info.caller) {
				text += "\n" + info.caller;
			}
			navigator.clipboard.writeText(text);
			removeMenu();
		}));
		// Menu item: Inspect variables in scope at this element
		var widget = findWidget(event.target);
		if(widget) {
			menu.appendChild(makeMenuItem("Inspect variables", function() {
				var vars = collectVariables(widget);
				removeMenu();
				showVariableInspector(vars, menuX, menuY, info.element, widget);
			}));
		}
		// Menu item: Edit inline — opens a popup with the source text in a temp tiddler (hidden by default)
		if(!isNaN(info.charStart) && !isNaN(info.charEnd) && info.charEnd > info.charStart
			&& $tw.wiki.getTiddlerText("$:/config/wikilabs/SourcePositionTracking/ShowEditInline", "").trim() === "show") {
			menu.appendChild(makeMenuItem("Edit inline", function() {
				var sourceText = $tw.wiki.getTiddlerText(info.tiddler, "");
				var snippet = sourceText.substring(info.charStart, info.charEnd);
				var tempTitle = "$:/temp/sourcepos/edit";
				// Store edit metadata
				$tw.wiki.addTiddler(new $tw.Tiddler({
					title: tempTitle,
					text: snippet,
					"source-tiddler": info.tiddler,
					"source-start": String(info.charStart),
					"source-end": String(info.charEnd),
					"source-pos": info.raw
				}));
				removeMenu();
				// Remove any existing inline editor
				var existingEditor = document.getElementById("sourcepos-inline-editor");
				if(existingEditor) existingEditor.remove();
				// Load saved layout from data tiddler
				var editorLayoutTitle = "$:/temp/sourcepos/editor-layout";
				var editorLayout = $tw.wiki.getTiddler(editorLayoutTitle);
				var elFields = editorLayout ? editorLayout.fields : {};
				var popupWidth = Math.max(300, parseInt(elFields.width, 10) || 500);
				var popupHeight = Math.max(150, parseInt(elFields.height, 10) || 300);
				// Create the inline editor popup
				var popup = document.createElement("div");
				popup.id = "sourcepos-inline-editor";
				popup.style.cssText = "position:fixed;z-index:100000;background:#2a2a2a;color:#eee;border-radius:6px;padding:0;box-shadow:0 4px 16px rgba(0,0,0,0.5);display:flex;flex-direction:column;overflow:hidden;";
				popup.style.width = popupWidth + "px";
				popup.style.height = popupHeight + "px";
				// Header (draggable)
				var popupHeader = document.createElement("div");
				popupHeader.style.cssText = "padding:6px 12px;background:#3a3a3a;border-radius:6px 6px 0 0;font-family:monospace;font-size:12px;color:#ffd;display:flex;justify-content:space-between;align-items:center;cursor:move;flex-shrink:0;user-select:none;";
				var headerLabel = document.createElement("span");
				headerLabel.textContent = info.raw;
				popupHeader.appendChild(headerLabel);
				// Close button
				var closeBtn = document.createElement("span");
				closeBtn.textContent = "\u2715";
				closeBtn.style.cssText = "cursor:pointer;padding:2px 6px;border-radius:3px;font-size:14px;";
				closeBtn.addEventListener("mouseenter", function() { closeBtn.style.background = "rgba(255,255,255,0.2)"; });
				closeBtn.addEventListener("mouseleave", function() { closeBtn.style.background = ""; });
				closeBtn.addEventListener("click", function() { popup.remove(); });
				popupHeader.appendChild(closeBtn);
				popup.appendChild(popupHeader);
				// Textarea for editing — fills remaining space
				var editorArea = document.createElement("textarea");
				editorArea.value = snippet;
				editorArea.style.cssText = "flex:1;background:#1e1e1e;color:#d4d4d4;border:none;padding:8px 12px;font-family:monospace;font-size:13px;line-height:1.5;resize:none;box-sizing:border-box;outline:none;";
				popup.appendChild(editorArea);
				// Button bar
				var btnBar = document.createElement("div");
				btnBar.style.cssText = "padding:6px 12px;display:flex;justify-content:flex-end;gap:8px;border-top:1px solid #444;flex-shrink:0;";
				var cancelBtn = document.createElement("button");
				cancelBtn.textContent = "Cancel";
				cancelBtn.style.cssText = "padding:4px 12px;background:#555;color:#eee;border:none;border-radius:3px;cursor:pointer;font-size:12px;";
				cancelBtn.addEventListener("click", function() { popup.remove(); });
				btnBar.appendChild(cancelBtn);
				var applyBtn = document.createElement("button");
				applyBtn.textContent = "Apply";
				applyBtn.style.cssText = "padding:4px 12px;background:#2a7a2a;color:#fff;border:none;border-radius:3px;cursor:pointer;font-size:12px;";
				applyBtn.addEventListener("click", function() {
					var newText = editorArea.value;
					var tiddler = $tw.wiki.getTiddler(info.tiddler);
					if(tiddler) {
						var fullText = tiddler.fields.text || "";
						var updated = fullText.substring(0, info.charStart) + newText + fullText.substring(info.charEnd);
						$tw.wiki.addTiddler(new $tw.Tiddler(tiddler, { text: updated }, $tw.wiki.getModificationFields()));
					}
					popup.remove();
				});
				btnBar.appendChild(applyBtn);
				popup.appendChild(btnBar);
				// Resize handle (bottom-right corner)
				var resizeHandle = document.createElement("div");
				resizeHandle.style.cssText = "position:absolute;bottom:0;right:0;width:16px;height:16px;cursor:nwse-resize;";
				// Draw resize grip lines
				var grip = document.createElement("div");
				grip.style.cssText = "position:absolute;bottom:3px;right:3px;width:8px;height:8px;border-right:2px solid #666;border-bottom:2px solid #666;";
				resizeHandle.appendChild(grip);
				popup.appendChild(resizeHandle);
				document.body.appendChild(popup);
				// Position below the element
				var rect = info.element.getBoundingClientRect();
				var left = Math.max(4, Math.min(rect.left, window.innerWidth - popupWidth - 4));
				var top = rect.bottom + 4;
				if(top + popupHeight > window.innerHeight) {
					top = Math.max(4, rect.top - popupHeight - 4);
				}
				popup.style.left = left + "px";
				popup.style.top = top + "px";
				// Drag to move (via header)
				var dragStartX, dragStartY, dragOrigLeft, dragOrigTop;
				popupHeader.addEventListener("mousedown", function(e) {
					if(e.target === closeBtn) return;
					e.preventDefault();
					dragStartX = e.clientX;
					dragStartY = e.clientY;
					dragOrigLeft = parseInt(popup.style.left, 10);
					dragOrigTop = parseInt(popup.style.top, 10);
					var onDragMove = function(me) {
						popup.style.left = Math.max(0, dragOrigLeft + me.clientX - dragStartX) + "px";
						popup.style.top = Math.max(0, dragOrigTop + me.clientY - dragStartY) + "px";
					};
					var onDragEnd = function() {
						document.removeEventListener("mousemove", onDragMove);
						document.removeEventListener("mouseup", onDragEnd);
					};
					document.addEventListener("mousemove", onDragMove);
					document.addEventListener("mouseup", onDragEnd);
				});
				// Resize (via handle)
				resizeHandle.addEventListener("mousedown", function(e) {
					e.preventDefault();
					e.stopPropagation();
					sharedState.isResizing = true;
					var resizeStartX = e.clientX;
					var resizeStartY = e.clientY;
					var origW = popup.offsetWidth;
					var origH = popup.offsetHeight;
					var onResizeMove = function(me) {
						var newW = Math.max(300, origW + me.clientX - resizeStartX);
						var newH = Math.max(150, origH + me.clientY - resizeStartY);
						popup.style.width = newW + "px";
						popup.style.height = newH + "px";
					};
					var onResizeEnd = function() {
						sharedState.isResizing = false;
						document.removeEventListener("mousemove", onResizeMove);
						document.removeEventListener("mouseup", onResizeEnd);
						var el = $tw.wiki.getTiddler(editorLayoutTitle);
						var ef = el ? el.fields : { title: editorLayoutTitle };
						$tw.wiki.addTiddler(new $tw.Tiddler(ef, { title: editorLayoutTitle, width: String(popup.offsetWidth), height: String(popup.offsetHeight) }));
					};
					document.addEventListener("mousemove", onResizeMove);
					document.addEventListener("mouseup", onResizeEnd);
				});
				// Focus the textarea
				editorArea.focus();
				// Keyboard shortcuts: Escape = cancel, Ctrl+Enter = apply
				var onKeydown = function(e) {
					if(e.key === "Escape") {
						popup.remove();
						document.removeEventListener("keydown", onKeydown, true);
					} else if(e.key === "Enter" && e.ctrlKey) {
						e.preventDefault();
						applyBtn.click();
						document.removeEventListener("keydown", onKeydown, true);
					}
				};
				document.addEventListener("keydown", onKeydown, true);
			}));
		}
		// Menu item: Open source tiddler
		menu.appendChild(makeMenuItem("Open " + info.tiddler, function() {
			new $tw.Story().navigateTiddler(info.tiddler);
			removeMenu();
		}));
		// Optional menu item: "Edit at" — shown when config tiddler is set to "show"
		if(rangeInfo && $tw.wiki.getTiddlerText("$:/config/wikilabs/SourcePositionTracking/ShowEditMenuItem", "").trim() === "show") {
			menu.appendChild(makeMenuItem("Edit at " + info.range, editAtPosition));
		}
		// Menu items: Open each caller in the chain
		if(info.caller) {
			var callerLines = info.caller.split("\n");
			for(var ci = 0; ci < callerLines.length; ci++) {
				var callerTitle = callerLines[ci].replace(/^\u2190\s*/, "").trim();
				if(callerTitle && callerTitle !== info.tiddler) {
					(function(title) {
						menu.appendChild(makeMenuItem("Open \u2190 " + title, function() {
							new $tw.Story().navigateTiddler(title);
							removeMenu();
						}));
					})(callerTitle);
				}
			}
		}
		document.body.appendChild(menu);
		// Adjust position to fit within viewport
		var menuW = menu.offsetWidth;
		var menuH = menu.offsetHeight;
		// Horizontal: prefer right of mouse, fall back to left
		if(menuX + menuW > window.innerWidth) {
			menuX = Math.max(0, menuX - menuW);
		}
		// Vertical: prefer below mouse, fall back to above
		if(menuY + menuH > window.innerHeight) {
			menuY = Math.max(0, menuY - menuH);
		}
		menu.style.left = menuX + "px";
		menu.style.top = menuY + "px";
		// Close menu on click outside or Escape
		closeMenu = function(e) {
			if(!menu.contains(e.target)) {
				removeMenu();
			}
		};
		var menuHovered = false;
		menu.addEventListener("mouseenter", function() { menuHovered = true; });
		menu.addEventListener("mouseleave", function() { menuHovered = false; });
		closeOnEscape = function(e) {
			if(e.key === "Escape" && menuHovered) {
				removeMenu();
			}
		};
		setTimeout(function() {
			document.addEventListener("click", closeMenu, true);
			document.addEventListener("keydown", closeOnEscape, true);
		}, 0);
	}, true);
};
","type":"application/javascript","module-type":"startup"},"$:/plugins/wikilabs/devtools/source-viewer.js":{"title":"$:/plugins/wikilabs/devtools/source-viewer.js","text":"/*\
title: $:/plugins/wikilabs/devtools/source-viewer.js
type: application/javascript
module-type: library

Source Viewer: a floating, draggable, resizable modal that accumulates
source code entries from data-source-pos right-click actions.

\*/

"use strict";

var sourcePosUtils = require("$:/plugins/wikilabs/devtools/utils.js");
var sharedState = sourcePosUtils.state;

var MAX_SOURCE_ENTRIES = 100;

function getLayout() {
	var s = sharedState.viewerLayout;
	return {
		width: s.width || 600,
		height: s.height || 400,
		left: s.left !== undefined ? s.left : -1,
		top: s.top !== undefined ? s.top : 60
	};
}

function saveLayout(props) {
	for(var k in props) {
		sharedState.viewerLayout[k] = parseInt(props[k], 10);
	}
}

var viewer = null;
var entries = [];

var renderIconHTML = sourcePosUtils.renderIconHTML;

var editIconCache = "";
function getEditIconHTML() {
	if(!editIconCache) {
		editIconCache = renderIconHTML("{{$:/core/images/edit-button}}");
	}
	return editIconCache;
}

function getOrCreate() {
	if(viewer && document.body.contains(viewer)) {
		return viewer;
	}
	viewer = document.createElement("div");
	viewer.id = "sourcepos-source-viewer";
	viewer.style.cssText = "position:fixed;z-index:100000;background:#2a2a2a;color:#eee;border-radius:6px;padding:0;box-shadow:0 4px 16px rgba(0,0,0,0.5);display:flex;flex-direction:column;overflow:hidden;";
	// Click isolation handled by global capture handler in click-handler.js
	// Load saved layout
	var layout = getLayout();
	viewer.style.width = Math.max(300, layout.width) + "px";
	viewer.style.height = Math.max(150, layout.height) + "px";
	if(layout.left >= 0) {
		viewer.style.left = layout.left + "px";
	} else {
		viewer.style.right = "20px";
	}
	viewer.style.top = layout.top + "px";
	// Header
	var header = document.createElement("div");
	header.style.cssText = "padding:6px 12px;background:#3a3a3a;border-radius:6px 6px 0 0;font-family:monospace;font-size:13px;color:#ffd;display:flex;justify-content:space-between;align-items:center;cursor:move;flex-shrink:0;user-select:none;";
	var headerLabel = document.createElement("span");
	headerLabel.textContent = "Source Viewer";
	header.appendChild(headerLabel);
	var headerBtns = document.createElement("span");
	headerBtns.style.cssText = "display:flex;gap:8px;align-items:center;";
	// Clear all button
	var clearBtn = document.createElement("span");
	clearBtn.textContent = "Clear";
	clearBtn.style.cssText = "cursor:pointer;padding:2px 8px;border-radius:3px;font-size:11px;background:rgba(255,255,255,0.1);";
	clearBtn.addEventListener("mouseenter", function() { clearBtn.style.background = "rgba(255,255,255,0.25)"; });
	clearBtn.addEventListener("mouseleave", function() { clearBtn.style.background = "rgba(255,255,255,0.1)"; });
	clearBtn.addEventListener("click", function() {
		var headers = getAllHeaders();
		for(var i = 0; i < headers.length; i++) {
			if(headers[i]._unhighlightOrigin) headers[i]._unhighlightOrigin();
		}
		entries = [];
		snippetMap = {};
		var content = viewer.querySelector(".sourcepos-viewer-content");
		if(content) content.innerHTML = "";
	});
	headerBtns.appendChild(clearBtn);
	// Close button
	var closeBtn = document.createElement("span");
	closeBtn.textContent = "\u2715";
	closeBtn.style.cssText = "cursor:pointer;padding:2px 6px;border-radius:3px;font-size:14px;";
	closeBtn.addEventListener("mouseenter", function() { closeBtn.style.background = "rgba(255,255,255,0.2)"; });
	closeBtn.addEventListener("mouseleave", function() { closeBtn.style.background = ""; });
	closeBtn.addEventListener("click", function() {
		var headers = getAllHeaders();
		for(var i = 0; i < headers.length; i++) {
			if(headers[i]._unhighlightOrigin) headers[i]._unhighlightOrigin();
		}
		viewer.remove();
	});
	headerBtns.appendChild(closeBtn);
	header.appendChild(headerBtns);
	viewer.appendChild(header);
	// Scrollable content area
	var content = document.createElement("div");
	content.className = "sourcepos-viewer-content";
	content.style.cssText = "flex:1;overflow-y:auto;padding:0;font-family:monospace;font-size:12px;";
	viewer.appendChild(content);
	// Resize handle
	var resizeHandle = document.createElement("div");
	resizeHandle.style.cssText = "position:absolute;bottom:0;right:0;width:16px;height:16px;cursor:nwse-resize;";
	var grip = document.createElement("div");
	grip.style.cssText = "position:absolute;bottom:3px;right:3px;width:8px;height:8px;border-right:2px solid #666;border-bottom:2px solid #666;";
	resizeHandle.appendChild(grip);
	viewer.appendChild(resizeHandle);
	document.body.appendChild(viewer);
	// Drag to move
	header.addEventListener("mousedown", function(e) {
		if(e.target === closeBtn || e.target === clearBtn) return;
		e.preventDefault();
		var dragStartX = e.clientX;
		var dragStartY = e.clientY;
		var rect = viewer.getBoundingClientRect();
		var dragOrigLeft = rect.left;
		var dragOrigTop = rect.top;
		viewer.style.right = "auto";
		viewer.style.left = dragOrigLeft + "px";
		var onDragMove = function(me) {
			viewer.style.left = Math.max(0, dragOrigLeft + me.clientX - dragStartX) + "px";
			viewer.style.top = Math.max(0, dragOrigTop + me.clientY - dragStartY) + "px";
		};
		var onDragEnd = function() {
			document.removeEventListener("mousemove", onDragMove);
			document.removeEventListener("mouseup", onDragEnd);
			saveLayout({ left: String(parseInt(viewer.style.left, 10)), top: String(parseInt(viewer.style.top, 10)) });
		};
		document.addEventListener("mousemove", onDragMove);
		document.addEventListener("mouseup", onDragEnd);
	});
	// Resize
	resizeHandle.addEventListener("mousedown", function(e) {
		e.preventDefault();
		e.stopPropagation();
		var resizeStartX = e.clientX;
		var resizeStartY = e.clientY;
		var origW = viewer.offsetWidth;
		var origH = viewer.offsetHeight;
		var onResizeMove = function(me) {
			viewer.style.width = Math.max(300, origW + me.clientX - resizeStartX) + "px";
			viewer.style.height = Math.max(150, origH + me.clientY - resizeStartY) + "px";
		};
		var onResizeEnd = function() {
			document.removeEventListener("mousemove", onResizeMove);
			document.removeEventListener("mouseup", onResizeEnd);
			saveLayout({ width: String(viewer.offsetWidth), height: String(viewer.offsetHeight) });
		};
		document.addEventListener("mousemove", onResizeMove);
		document.addEventListener("mouseup", onResizeEnd);
	});
	return viewer;
}

// Build the snippet and proc name for a given info
function getSnippetInfo(info) {
	var sourceText = $tw.wiki.getTiddlerText(info.tiddler, "");
	var snippet = "";
	var procName = "";
	var snippetKey = "";
	if(!isNaN(info.charStart) && !isNaN(info.charEnd) && info.charEnd > info.charStart) {
		var defStart = -1;
		var defEnd = -1;
		var textBefore = sourceText.substring(0, info.charStart);
		var defMatch = textBefore.match(/[\s\S]*\\(procedure|define|widget|function)\s+([^\s(]+)/);
		if(defMatch) {
			defStart = textBefore.lastIndexOf("\\" + defMatch[1]);
			procName = defMatch[2];
			var endPattern = "\\end";
			var endIdx = sourceText.indexOf(endPattern, info.charEnd);
			defEnd = (endIdx !== -1) ? endIdx + endPattern.length : sourceText.length;
		}
		if(defStart >= 0 && defEnd > defStart) {
			snippet = sourceText.substring(defStart, defEnd);
			snippetKey = info.tiddler + ":" + defStart + "-" + defEnd;
		} else {
			snippet = sourceText.substring(info.charStart, info.charEnd);
			snippetKey = info.tiddler + ":" + info.charStart + "-" + info.charEnd;
		}
	} else {
		snippet = "(no char range available)";
		snippetKey = info.tiddler + ":no-range";
	}
	return { snippet: snippet, procName: procName, key: snippetKey };
}

// Create a header row for an entry
function createHeaderRow(info, procName, editAtPosition) {
	var sourceElement = info.element;
	var highlightClass = "sourcepos-highlight-origin";
	var row = document.createElement("div");
	row.style.cssText = "padding:4px 12px;background:#333;color:#ffd;font-size:11px;display:flex;justify-content:space-between;align-items:center;cursor:pointer;";
	row._sourceElement = sourceElement;
	var blinkTimer = null;
	row._highlightOrigin = function() {
		if(!sourceElement || !document.body.contains(sourceElement)) return;
		// Blink 3 times in red, then stay with blue highlight
		var blinkCount = 0;
		var blinkClass = "sourcepos-highlight-blink";
		function doBlink() {
			if(blinkCount < 6) {
				sourceElement.classList.toggle(blinkClass);
				blinkCount++;
				blinkTimer = setTimeout(doBlink, 150);
			} else {
				sourceElement.classList.remove(blinkClass);
				sourceElement.classList.add(highlightClass);
				blinkTimer = null;
			}
		}
		// Clear any previous blink
		if(blinkTimer) { clearTimeout(blinkTimer); blinkTimer = null; }
		sourceElement.classList.remove(blinkClass);
		sourceElement.classList.remove(highlightClass);
		doBlink();
	};
	row._unhighlightOrigin = function() {
		if(blinkTimer) { clearTimeout(blinkTimer); blinkTimer = null; }
		if(sourceElement) {
			sourceElement.classList.remove(highlightClass);
			sourceElement.classList.remove("sourcepos-highlight-blink");
		}
	};
	var label = document.createElement("span");
	label.textContent = info.raw;
	if(procName) {
		label.textContent += "  \u2014 " + procName;
	}
	if(info.context) {
		label.textContent += "  \u00BB " + info.context;
	}
	row.appendChild(label);
	var btns = document.createElement("span");
	btns.style.cssText = "display:flex;gap:4px;align-items:center;";
	// Edit button
	if(editAtPosition && !isNaN(info.charStart) && !isNaN(info.charEnd)) {
		var editBtn = document.createElement("span");
		editBtn.innerHTML = getEditIconHTML();
		editBtn.title = "Edit at " + info.range;
		editBtn.style.cssText = "cursor:pointer;fill:#ffd;font-size:0;line-height:0;padding:1px 3px;border-radius:3px;background:rgba(255,255,255,0.1);";
		var svg = editBtn.querySelector("svg");
		if(svg) { svg.setAttribute("width", "12px"); svg.setAttribute("height", "12px"); }
		editBtn.addEventListener("mouseenter", function() { editBtn.style.background = "rgba(255,255,255,0.25)"; });
		editBtn.addEventListener("mouseleave", function() { editBtn.style.background = "rgba(255,255,255,0.1)"; });
		editBtn.addEventListener("click", function(e) { e.stopPropagation(); editAtPosition(); });
		btns.appendChild(editBtn);
	}
	// Remove header row button
	var removeBtn = document.createElement("span");
	removeBtn.textContent = "\u2715";
	removeBtn.style.cssText = "cursor:pointer;padding:1px 4px;border-radius:3px;font-size:11px;color:#999;";
	removeBtn.addEventListener("mouseenter", function() { removeBtn.style.color = "#fff"; });
	removeBtn.addEventListener("mouseleave", function() { removeBtn.style.color = "#999"; });
	removeBtn.addEventListener("click", function(e) {
		e.stopPropagation();
		row._unhighlightOrigin();
		var entry = row.parentNode;
		row.remove();
		// If no headers remain, remove the whole entry
		if(entry && !entry.querySelector(".sourcepos-entry-header")) {
			var idx = entries.indexOf(entry);
			if(idx !== -1) entries.splice(idx, 1);
			entry.remove();
			// Also remove from snippetMap
			for(var k in snippetMap) {
				if(snippetMap[k] === entry) {
					delete snippetMap[k];
					break;
				}
			}
		}
		updateAutoHighlight();
	});
	btns.appendChild(removeBtn);
	row.appendChild(btns);
	row.className = "sourcepos-entry-header";
	// Highlight on hover
	row.addEventListener("mouseenter", row._highlightOrigin);
	row.addEventListener("mouseleave", row._unhighlightOrigin);
	return row;
}

// Map snippet keys to existing entry DOM elements
var snippetMap = {};

function addEntry(info, editAtPosition) {
	var v = getOrCreate();
	var content = v.querySelector(".sourcepos-viewer-content");
	var si = getSnippetInfo(info);
	// Check if this snippet already exists
	var existing = snippetMap[si.key];
	if(existing && document.body.contains(existing)) {
		// Add a new header row above the existing code block
		var headerRow = createHeaderRow(info, si.procName, editAtPosition);
		var codeBlock = existing.querySelector("pre");
		if(codeBlock) {
			existing.insertBefore(headerRow, codeBlock);
		} else {
			existing.appendChild(headerRow);
		}
		// Move entry to top
		if(content.firstChild !== existing) {
			content.insertBefore(existing, content.firstChild);
		}
		updateAutoHighlight();
		return;
	}
	// Cap entries
	if(entries.length >= MAX_SOURCE_ENTRIES) {
		var oldest = content.lastChild;
		if(oldest) {
			// Clean up highlights for all headers in the removed entry
			var oldHeaders = oldest.querySelectorAll(".sourcepos-entry-header");
			for(var h = 0; h < oldHeaders.length; h++) {
				if(oldHeaders[h]._unhighlightOrigin) oldHeaders[h]._unhighlightOrigin();
			}
			// Remove from snippetMap
			for(var k in snippetMap) {
				if(snippetMap[k] === oldest) {
					delete snippetMap[k];
					break;
				}
			}
			oldest.remove();
			entries.pop();
		}
	}
	// Create new entry
	var entry = document.createElement("div");
	entry.style.cssText = "border-bottom:1px solid #444;";
	// Header row
	var headerRow = createHeaderRow(info, si.procName, editAtPosition);
	entry.appendChild(headerRow);
	// Source code (read-only)
	var code = document.createElement("pre");
	code.style.cssText = "margin:0;padding:6px 12px;background:#1e1e1e;color:#d4d4d4;font-size:12px;line-height:1.4;white-space:pre-wrap;word-wrap:break-word;overflow-x:auto;";
	code.textContent = si.snippet;
	entry.appendChild(code);
	// Prepend at top
	if(content.firstChild) {
		content.insertBefore(entry, content.firstChild);
	} else {
		content.appendChild(entry);
	}
	entries.unshift(entry);
	snippetMap[si.key] = entry;
	updateAutoHighlight();
}

// Get all header rows across all entries
function getAllHeaders() {
	var headers = [];
	for(var i = 0; i < entries.length; i++) {
		var rows = entries[i].querySelectorAll(".sourcepos-entry-header");
		for(var j = 0; j < rows.length; j++) {
			headers.push(rows[j]);
		}
	}
	return headers;
}

// When only 1 header total, auto-highlight its origin element
function updateAutoHighlight() {
	var headers = getAllHeaders();
	// Clear all highlights first
	for(var i = 0; i < headers.length; i++) {
		if(headers[i]._unhighlightOrigin) headers[i]._unhighlightOrigin();
	}
	// Auto-highlight if exactly 1 header
	if(headers.length === 1 && headers[0]._highlightOrigin) {
		headers[0]._highlightOrigin();
	}
}

exports.addEntry = addEntry;
","type":"application/javascript","module-type":"library"},"$:/plugins/wikilabs/devtools/startup.js":{"title":"$:/plugins/wikilabs/devtools/startup.js","text":"/*\
title: $:/plugins/wikilabs/devtools/startup.js
type: application/javascript
module-type: startup

Source position tracking plugin. Adds data-source-pos attributes to rendered
HTML elements and links, tracing each back to its source tiddler and line range.

All tracking logic lives in this plugin — no core modifications required.
Uses th-dom-rendering-element and th-dom-rendering-link hooks for elements/links,
and monkey-patches the transclude widget to set sourceContext for tiddler attribution.

\*/

"use strict";

var sourcePosUtils = require("$:/plugins/wikilabs/devtools/utils.js");

exports.name = "sourcepos";
exports.before = ["startup"];
exports.after = ["load-modules"];
exports.synchronous = true;

// Caches (reset on each tracking toggle to avoid stale data)
var lineCache = {};
var headerCache = {};
var bodyOffsetCache = {};

// Build array of line-start character offsets for a tiddler's text
function getLineOffsets(title) {
	if(lineCache[title]) return lineCache[title];
	var text = $tw.wiki.getTiddlerText(title, "");
	var offsets = [0];
	for(var i = 0; i < text.length; i++) {
		if(text.charAt(i) === "\n") offsets.push(i + 1);
	}
	lineCache[title] = offsets;
	return offsets;
}

// Binary search: character offset → 1-based line number
function charToLine(offsets, charPos) {
	var lo = 0, hi = offsets.length - 1;
	while(lo < hi) {
		var mid = (lo + hi + 1) >> 1;
		if(offsets[mid] <= charPos) lo = mid; else hi = mid - 1;
	}
	return lo + 1;
}

// Count .tid file header lines (fields excluding text + 1 blank separator)
function getTidHeaderLines(title) {
	if(headerCache[title] !== undefined) return headerCache[title];
	var tiddler = $tw.wiki.getTiddler(title);
	if(!tiddler) {
		headerCache[title] = 0;
		return 0;
	}
	// Exclude fields not written to .tid files: 'text' (body), 'bag' (excluded by
	// $:/core/templates/tid-tiddler), and 'revision' (sync adapter runtime field)
	var exclude = {"text": true, "bag": true, "revision": true};
	var fieldCount = 0;
	for(var f in tiddler.fields) {
		if(!exclude[f]) fieldCount++;
	}
	headerCache[title] = fieldCount + 1; // fields + empty line
	return headerCache[title];
}

// Find the character offset where a variable body starts within the full tiddler text
function findBodyOffset(title, bodyText) {
	var key = title + "\0" + bodyText.length;
	if(bodyOffsetCache[key] !== undefined) return bodyOffsetCache[key];
	var fullText = $tw.wiki.getTiddlerText(title, "");
	var idx = fullText.indexOf(bodyText);
	bodyOffsetCache[key] = idx >= 0 ? idx : 0;
	return bodyOffsetCache[key];
}

// Walk up the widget tree to find the nearest sourceContext
function getSourceInfo(widget) {
	var w = widget;
	while(w) {
		if(w.sourceContext !== undefined) {
			return { title: w.sourceContext, offset: w.sourceContextOffset || 0 };
		}
		w = w.parentWidget;
	}
	return null;
}

// Build the transclusion caller chain by walking up sourceContext changes.
// Stops at the first non-system tiddler to avoid showing TW's internal
// UI template chain ($:/core/ui/ViewTemplate, PageTemplate, etc.)
function buildCallerChain(widget) {
	var chain = [];
	var lastContext = null;
	var w = widget;
	while(w) {
		if(w.sourceContext !== undefined && w.sourceContext !== lastContext) {
			if(lastContext !== null) {
				chain.push(w.sourceContext);
			}
			lastContext = w.sourceContext;
		}
		w = w.parentWidget;
	}
	return chain;
}

// Build the data-source-pos value with line numbers: L{start}-L{end}@tiddlerTitle
function buildPosInfo(widget) {
	var ptn = widget.parseTreeNode;
	if(!ptn || ptn.start === undefined) {
		return null;
	}
	var info = getSourceInfo(widget);
	if(!info) {
		return null;
	}
	var offsets = getLineOffsets(info.title);
	var absStart = ptn.start + info.offset;
	var absEnd = (ptn.end || ptn.start) + info.offset;
	var startLine = charToLine(offsets, absStart);
	var endLine = charToLine(offsets, absEnd);
	var headerOffset = getTidHeaderLines(info.title);
	return sourcePosUtils.format(startLine + headerOffset, endLine + headerOffset, info.title);
}

exports.startup = function() {
	// --- Prototype patches for core widgets (no core modifications required) ---

	// Patch setVariable to store sourceTitle for variable-to-tiddler attribution
	var Widget = require("$:/core/modules/widgets/widget.js").widget;
	var origSetVariable = Widget.prototype.setVariable;
	Widget.prototype.setVariable = function(name, value, params, isMacroDefinition, options) {
		origSetVariable.call(this, name, value, params, isMacroDefinition, options);
		if(options && options.sourceTitle && this.variables[name]) {
			this.variables[name].sourceTitle = options.sourceTitle;
		}
	};

	// Patch importvariables to propagate sourceTitle through imported globals
	var ImportVariablesWidget = require("$:/core/modules/widgets/importvariables.js").importvariables;
	var origImportExecute = ImportVariablesWidget.prototype.execute;
	ImportVariablesWidget.prototype.execute = function(tiddlerList) {
		origImportExecute.call(this, tiddlerList);
		// Build map: variable name → source tiddler title
		var varSourceMap = Object.create(null);
		var self = this;
		$tw.utils.each(this.tiddlerList, function(title) {
			var parser = self.wiki.parseTiddler(title, {parseAsInline: true, configTrimWhiteSpace: false});
			if(parser) {
				var node = parser.tree[0];
				while(node && ["setvariable", "set", "parameters", "void"].indexOf(node.type) !== -1) {
					if(node.attributes && node.attributes.name) {
						varSourceMap[node.attributes.name.value] = title;
					}
					node = node.children && node.children[0];
				}
			}
		});
		// Walk the widget chain and tag variables that lack sourceTitle
		var ptr = this;
		while(ptr) {
			if(ptr.variables) {
				var ownKeys = Object.keys(ptr.variables);
				for(var ki = 0; ki < ownKeys.length; ki++) {
					var v = ptr.variables[ownKeys[ki]];
					if(v && !v.sourceTitle && varSourceMap[ownKeys[ki]]) {
						v.sourceTitle = varSourceMap[ownKeys[ki]];
					}
				}
			}
			ptr = (ptr.children && ptr.children.length === 1) ? ptr.children[0] : null;
		}
	};

	// Patch link widget to invoke th-dom-rendering-link hook
	var LinkWidget = require("$:/core/modules/widgets/link.js").link;
	var origRenderLink = LinkWidget.prototype.renderLink;
	LinkWidget.prototype.renderLink = function(parent, nextSibling) {
		origRenderLink.call(this, parent, nextSibling);
		if(this.domNodes.length > 0) {
			$tw.hooks.invokeHook("th-dom-rendering-link", this.domNodes[this.domNodes.length - 1], this);
		}
	};

	// Patch codeblock widget to invoke th-dom-rendering-codeblock hook
	var CodeBlockWidget = require("$:/core/modules/widgets/codeblock.js").codeblock;
	var origCodeBlockRender = CodeBlockWidget.prototype.render;
	CodeBlockWidget.prototype.render = function(parent, nextSibling) {
		origCodeBlockRender.call(this, parent, nextSibling);
		if(this.domNodes.length > 0) {
			$tw.hooks.invokeHook("th-dom-rendering-codeblock", this.domNodes[this.domNodes.length - 1], this);
		}
	};

	// --- Source position tracking setup ---

	// Set initial state from config
	updateTracking();
	// Watch for config changes
	$tw.wiki.addEventListener("change", function(changes) {
		if(changes["$:/config/wikilabs/SourcePositionTracking"]) {
			updateTracking();
		}
	});
	// Shared hook logic for elements and links
	var addSourcePos = function(domNode, widget) {
		if($tw.wiki.trackSourcePositions) {
			var posInfo = buildPosInfo(widget);
			if(posInfo) {
				domNode.setAttribute("data-source-pos", posInfo);
				// Store raw char positions for precise editor selection
				// Offset adjusts for macro body position within the tiddler text
				var ptn = widget.parseTreeNode;
				var srcInfo = getSourceInfo(widget);
				var charOffset = srcInfo ? srcInfo.offset : 0;
				if(ptn && ptn.start !== undefined) {
					domNode.setAttribute("data-source-start", ptn.start + charOffset);
					domNode.setAttribute("data-source-end", (ptn.end || ptn.start) + charOffset);
				}
				var callers = buildCallerChain(widget);
				// Add currentTiddler context so repeated list items can be distinguished
				var ct = widget.getVariable("currentTiddler");
				var info = getSourceInfo(widget);
				if(ct && info && ct !== info.title) {
					domNode.setAttribute("data-source-context", ct);
				}
				if(callers.length > 0) {
					domNode.setAttribute("data-source-caller", callers.map(function(c) { return "\u2190 " + c; }).join("\n"));
				}
			}
			// Store widget back-reference for variable inspection
			domNode._twWidget = widget;
		}
		return domNode;
	};
	// Hook: add data-source-pos to element DOM nodes
	$tw.hooks.addHook("th-dom-rendering-element", addSourcePos);
	// Hook: add data-source-pos to link DOM nodes
	$tw.hooks.addHook("th-dom-rendering-link", addSourcePos);
	// Hook: add data-source-pos to codeblock DOM nodes
	$tw.hooks.addHook("th-dom-rendering-codeblock", addSourcePos);
	// Monkey-patch transclude widget to set sourceContext for position attribution
	var TranscludeWidget = require("$:/core/modules/widgets/transclude.js").transclude;
	var origExecute = TranscludeWidget.prototype.execute;
	TranscludeWidget.prototype.execute = function() {
		origExecute.call(this);
		// Set source context after execute so transcludeTitle/transcludeVariable are resolved
		if($tw.wiki.trackSourcePositions) {
			// Check transcludeVariable first — when both $variable and $tiddler are set,
			// the parse tree comes from the variable definition, not the tiddler
			if(this.transcludeVariable) {
				var varInfo = this.getVariableInfo(this.transcludeVariable);
				var srcVar = varInfo && varInfo.srcVariable;
				this.sourceContext = (srcVar && srcVar.sourceTitle) || this.transcludeVariable;
				this.sourceContextOffset = 0;
				if(srcVar && srcVar.sourceTitle && srcVar.value) {
					this.sourceContextOffset = findBodyOffset(srcVar.sourceTitle, srcVar.value);
				}
			} else if(this.transcludeTitle) {
				this.sourceContext = this.transcludeTitle;
				this.sourceContextOffset = 0;
			}
		}
	};
};

function updateTracking() {
	var enabled = $tw.wiki.getTiddlerText("$:/config/wikilabs/SourcePositionTracking", "no").trim() === "yes";
	$tw.wiki.trackSourcePositions = enabled;
	// Clear caches when tracking state changes
	if(enabled) {
		lineCache = {};
		headerCache = {};
		bodyOffsetCache = {};
	}
}
